const ZenithTelemetry=(function(){const e={debugMode:true,mixpanelToken:"YOUR_MIXPANEL_TOKEN",googleAnalyticsId:"G-XXXXXXXXXX",endpointUrl:"https://api.zenithfocus.com/v1/telemetry"};function t(t,n={}){const o={event:t,timestamp:new Date().toISOString(),properties:{platform:"Web SPA",version:"1.0.0",viewport:`${window.innerWidth}x${window.innerHeight}`,...n}};if(e.debugMode){console.log(`[Zenith Telemetry] 📊 Tracked: "${t}"`,o.properties)}if(e.endpointUrl){fetch(e.endpointUrl,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(o)}).catch(e=>{if(e.debugMode){console.log("[Zenith Telemetry] REST pipeline bypassed (running in secure local mode).")}})}if(window.gtag){window.gtag('event',t,o.properties)}if(window.mixpanel){window.mixpanel.track(t,o.properties)}}return{trackStudySession:function(e,n){t("study_session_accumulated",{durationMinutes:e,studySubject:n})},trackPomodoroCompleted:function(e,n){t("pomodoro_completed",{timerMode:e,sessionLength:n})},trackDistractionIncident:function(e,n){t("distraction_incident",{distractionType:e,details:n})},trackBurnoutWarning:function(e,n){t("burnout_fatigue_warning",{currentBurnout:e,currentFocus:n})},trackSubjectChanged:function(e){t("subject_changed",{activeSubject:e})},trackBreathingExerciseStarted:function(){t("breathing_exercise_initiated",{type:"Box Breathing"})}}})();
